INSERT INTO `v1_ab17f7f082cf5b774642022a4a098dd2f5fc66bf0d050d5c9e36c51f1e2f0164` VALUES (1011, 1, 1, 1, "イベントでは、特別なストーリーをお楽しみいただけます。\n閲覧可能なストーリーを読むと、次のお話が解放されていきますよ。\nストーリーの閲覧によって達成されるミッションもあるのだとか。");
INSERT INTO `v1_ab17f7f082cf5b774642022a4a098dd2f5fc66bf0d050d5c9e36c51f1e2f0164` VALUES (1021, 2, 1, 2, "イベントクエストやボスバトルに挑戦してみましょう。ボスバトルは\n特定のイベントストーリーを閲覧するか、イベントクエスト・ボス画面で\n「解放する」を選択すると挑戦可能になりますよ。");
INSERT INTO `v1_ab17f7f082cf5b774642022a4a098dd2f5fc66bf0d050d5c9e36c51f1e2f0164` VALUES (1041, 4, 1, 4, "報酬交換では「イベント報酬券」と様々なアイテムを交換できます。\n目玉となるリセット対象報酬を引くことで、より多くのアイテムが\n獲得できる次のラインナップへと進めるそうです。");
INSERT INTO `v1_ab17f7f082cf5b774642022a4a098dd2f5fc66bf0d050d5c9e36c51f1e2f0164` VALUES (1051, 5, 1, 5, "ボスバトルには３種の難易度がございます。\n各難易度ごとにボスの強さやバトルの特徴が異なりますので、\n準備をしっかりして、気を引き締めて挑みましょう。");
INSERT INTO `v1_ab17f7f082cf5b774642022a4a098dd2f5fc66bf0d050d5c9e36c51f1e2f0164` VALUES (2011, 1, 2, 1, "イベントでは、特別なストーリーをお楽しみいただけます。\n閲覧可能なストーリーを読むと、次のお話が解放されていきますよ。\nストーリーの閲覧によって達成されるミッションもあるのだとか。");
INSERT INTO `v1_ab17f7f082cf5b774642022a4a098dd2f5fc66bf0d050d5c9e36c51f1e2f0164` VALUES (2021, 2, 2, 2, "イベントクエストやボスバトルに挑戦してみましょう。ボスバトルは\n特定のイベントストーリーを閲覧するか、イベントクエスト・ボス画面で\n「解放する」を選択すると挑戦可能になりますよ。");
INSERT INTO `v1_ab17f7f082cf5b774642022a4a098dd2f5fc66bf0d050d5c9e36c51f1e2f0164` VALUES (2041, 4, 2, 4, "報酬交換では「イベント報酬券」と様々なアイテムを交換できます。\n目玉となるリセット対象報酬を引くことで、より多くのアイテムが\n獲得できる次のラインナップへと進めるそうです。");
INSERT INTO `v1_ab17f7f082cf5b774642022a4a098dd2f5fc66bf0d050d5c9e36c51f1e2f0164` VALUES (2051, 5, 2, 5, "ボスバトルには２種の難易度がございます。\n各難易度ごとにボスの強さやバトルの特徴が異なりますので、\n準備をしっかりして、気を引き締めて挑みましょう。");
INSERT INTO `v1_ab17f7f082cf5b774642022a4a098dd2f5fc66bf0d050d5c9e36c51f1e2f0164` VALUES (2061, 6, 2, 6, "ボスバトルには２種の難易度がございます。\n各難易度ごとにボスの強さやバトルの特徴が異なりますので、\n準備をしっかりして、気を引き締めて挑みましょう。");
